const result = await installLanguagePackages({
    language: "nodejs",
    packages: ["cd frontend && npm install"]
});
console.log(result.message);

const result = await installLanguagePackages({
    language: "python",
    packages: ["psycopg2-binary>=2.9,<3.0"]
});
console.log(result.message);
console.log(result.output?.slice(-300));

// Set up backend workflow on port 8000
const backend = await configureWorkflow({
    name: "Backend API",
    command: "cd backend2 && python manage.py runserver localhost:8000",
    waitForPort: 8000,
    outputType: "console"
});
console.log("Backend:", backend);

const status = await getWorkflowStatus({ name: "Backend API" });
console.log("State:", status.state);
console.log("Output:", status.output);
console.log("Ports:", status.openPorts);

// Set up frontend workflow on port 5000
const frontend = await configureWorkflow({
    name: "Start application",
    command: "cd frontend && npm run dev",
    waitForPort: 5000,
    outputType: "webview"
});
console.log("Frontend:", frontend.success, frontend.message?.slice(0, 200));

// Reconfigure backend without waitForPort since localhost isn't externally reachable
const backend = await configureWorkflow({
    name: "Backend API",
    command: "cd backend2 && python manage.py runserver localhost:8000",
    outputType: "console",
    autoStart: true
});
console.log("Backend:", backend.success, backend.message?.slice(0, 200));

// This is a full-stack app: frontend (Vite/React) + backend (Django)
// For deployment, we'll serve the built frontend statically and run Django for the API
// Use autoscale with a build step for the frontend and gunicorn for the backend

// First install gunicorn
const gunicorn = await installLanguagePackages({
    language: "python",
    packages: ["gunicorn>=23.0,<24.0"]
});
console.log("Gunicorn:", gunicorn.message);

// Configure deployment: build the frontend, then serve with a combined startup script
const result = await deployConfig({
    deploymentTarget: "autoscale",
    build: ["bash", "-c", "cd frontend && npm run build"],
    run: ["bash", "-c", "cd backend2 && python manage.py migrate --run-syncdb && gunicorn --bind=0.0.0.0:5000 --reuse-port digital_wallet.wsgi:application"]
});
console.log(result.success, result.message);

