    14→// Request Interceptor: Inject Auth Token
    15→baseClient.interceptors.request.use(
    16→  (config) => {
    17→    const token = localStorage.getItem('authToken') || localStorage.getItem('auth_token');
    18→    if (token) {
    19→      config.headers.Authorization = `Bearer ${token}`;
    20→    }
    21→    return config;
    22→  },
    23→  (error) => Promise.reject(error)
    24→);
    25→
    26→// Response Interceptor: Handle Errors & Auto-Logout on Session Expiry
    27→baseClient.interceptors.response.use(
    28→  (response) => response,
    29→  (error) => {
    30→    const status = error.response?.status;
    31→
    32→    if (status === 401) {
    33→      // Clear session data
    34→      localStorage.removeItem('authToken');
    35→      localStorage.removeItem('auth_token');
    36→      localStorage.removeItem('refreshToken');
    37→      localStorage.removeItem('user');
    38→      localStorage.removeItem('userEmail');
    39→      localStorage.removeItem('userName');
    40→      localStorage.removeItem('userRole');
    41→      localStorage.removeItem('userRoles');
    42→
    43→      // Fire a custom event so the auth hook can update its React state
    44→      window.dispatchEvent(new CustomEvent('auth:logout'));
    45→
    46→      // Only redirect if not already on login/register pages (avoid redirect loops)
    47→      const publicPaths = ['/login', '/register', '/auth/', '/'];
    48→      const currentPath = window.location.pathname;
    49→      const isPublic = publicPaths.some(p => currentPath.startsWith(p));
    50→
    51→      if (!isPublic && !currentPath.startsWith('/login')) {
    52→        toast.error('Session expired. Please log in again.');
    53→        window.location.href = '/?openLogin=true';
    54→      }
    55→
    56→      return Promise.reject(error);
    57→    }
    58→
    59→    if (status === 429) {
    60→      toast.error('Too many requests. Please wait a moment before trying again.');
    61→    } else if (status === 403) {
    62→      const errorCode = error.response?.data?.error;
    63→      const suppressedCodes = ['PENDING_APPROVAL', 'REJECTED'];
    64→      if (!errorCode || !suppressedCodes.includes(errorCode)) {
    65→        toast.error("You don't have permission to perform this action.");
    66→      }
    67→    } else if (status === 404) {
    68→      // Silently handle 404 - let the calling code handle it
    69→    } else if (status && status >= 500) {
    70→      toast.error('Server error. Please try again later.');
    71→    }
    72→
    73→    return Promise.reject(error);
    74→  }
    75→);
