     1→import type { ApiConfig } from './config';
     2→import type { ApiErrorResponse } from './types';
     3→
     4→export class ApiError extends Error {
     5→  constructor(
     6→    message: string,
     7→    public readonly status: number,
     8→    public readonly body?: ApiErrorResponse,
     9→  ) {
    10→    super(message);
    11→    this.name = 'ApiError';
    12→  }
    13→}
    14→
    15→export class ApiClient {
    16→  private config: ApiConfig;
    17→
    18→  constructor(config: ApiConfig) {
    19→    this.config = config;
    20→  }
    21→
    22→  getConfig(): ApiConfig { return { ...this.config }; }
    23→  setBaseUrl(url: string): void { this.config.baseUrl = url; }
    24→
    25→  async get<T>(path: string, token?: string): Promise<T> {
    26→    return this.request<T>(path, 'GET', undefined, token);
    27→  }
    28→  async post<T>(path: string, body?: unknown, token?: string): Promise<T> {
    29→    return this.request<T>(path, 'POST', body, token);
    30→  }
    31→  async put<T>(path: string, body?: unknown, token?: string): Promise<T> {
    32→    return this.request<T>(path, 'PUT', body, token);
    33→  }
    34→  async patch<T>(path: string, body?: unknown, token?: string): Promise<T> {
    35→    return this.request<T>(path, 'PATCH', body, token);
    36→  }
    37→  async delete<T>(path: string, token?: string): Promise<T> {
    38→    return this.request<T>(path, 'DELETE', undefined, token);
    39→  }
    40→  async postFormData<T>(path: string, formData: FormData, token?: string): Promise<T> {
    41→    return this.requestFormData<T>(path, 'POST', formData, token);
    42→  }
    43→
    44→  private async request<T>(
    45→    path: string,
    46→    method: string,
    47→    body?: unknown,
    48→    token?: string,
    49→    timeoutMs = 30000,
    50→  ): Promise<T> {
    51→    const headers: Record<string, string> = {
    52→      Accept: 'application/json',
    53→      'Content-Type': 'application/json',
    54→    };
    55→    if (token) headers['Authorization'] = `Bearer ${token}`;
    56→
    57→    const base = this.config.baseUrl.endsWith('/') ? this.config.baseUrl.slice(0, -1) : this.config.baseUrl;
    58→    const url = `${base}${path.startsWith('/') ? path : `/${path}`}`;
    59→
    60→    const controller = new AbortController();
    61→    const timer = setTimeout(() => controller.abort(), timeoutMs);
    62→
    63→    try {
    64→      const res = await fetch(url, {
    65→        method,
    66→        headers,
    67→        body: body != null ? JSON.stringify(body) : undefined,
    68→        signal: controller.signal,
    69→      });
    70→      clearTimeout(timer);
    71→
    72→      const isJson = (res.headers.get('content-type') ?? '').includes('application/json');
    73→      const payload: unknown = isJson ? await res.json() : { detail: await res.text() };
    74→
    75→      if (!res.ok) {
    76→        let msg = 'Request failed';
    77→        if (payload && typeof payload === 'object') {
    78→          const p = payload as Record<string, unknown>;
    79→          msg = String(p.detail ?? p.message ?? p.error ?? msg);
    80→        }
    81→        throw new ApiError(msg, res.status, payload as ApiErrorResponse);
    82→      }
    83→      return payload as T;
    84→    } catch (err) {
    85→      clearTimeout(timer);
    86→      if (err instanceof ApiError) throw err;
    87→      if (err instanceof Error && err.name === 'AbortError') {
    88→        throw new ApiError('Request timed out.', -2);
    89→      }
    90→      const isNetwork =
    91→        err instanceof TypeError &&
    92→        (err.message.includes('Network request failed') ||
    93→          err.message.includes('Failed to fetch') ||
    94→          err.message.includes('NetworkError'));
    95→      const connErr = new ApiError(
    96→        isNetwork
    97→          ? 'Connection failed. Server unreachable or no internet.'
    98→          : 'Connection failed. Check your internet connection.',
    99→        -1,
   100→      );
   101→      if (isNetwork) connErr.name = 'ConnectionError';
   102→      throw connErr;
   103→    }
   104→  }
