     1→import AsyncStorage from '@react-native-async-storage/async-storage';
     2→import { authApi } from '../auth/authApi';
     3→import type { SyncRequest, SyncResponse } from '../auth/authApi';
     4→
     5→const KEYS = {
     6→  SYNC_TOKEN: 'sync_token',
     7→  LAST_SYNC: 'last_sync_timestamp',
     8→  OFFLINE_QUEUE: 'offline_queue',
     9→};
    10→
    11→export interface OfflineAction { id: string; type: string; data: unknown; timestamp: string; }
    12→
    13→export async function saveSyncToken(token: string): Promise<void> {
    14→  if (!token || token.length < 10) throw new Error('Invalid sync token');
    15→  await AsyncStorage.setItem(KEYS.SYNC_TOKEN, token);
    16→}
    17→
    18→export async function getSyncToken(): Promise<string | null> {
    19→  return AsyncStorage.getItem(KEYS.SYNC_TOKEN);
    20→}
    21→
    22→export async function syncData(): Promise<SyncResponse> {
    23→  const syncToken = await getSyncToken();
    24→  if (!syncToken) throw new Error('No sync token. Please register again.');
    25→
    26→  const [lastSync, offlineActions] = await Promise.all([
    27→    AsyncStorage.getItem(KEYS.LAST_SYNC).then(v => v ?? undefined),
    28→    getOfflineActions(),
    29→  ]);
    30→
    31→  const request: SyncRequest = { sync_token: syncToken, last_sync_timestamp: lastSync, offline_actions: offlineActions };
    32→  const response = await authApi.syncData(request);
    33→
    34→  // Rotate token if backend provided a new one
    35→  if (response.new_sync_token) await saveSyncToken(response.new_sync_token);
    36→
    37→  // Clear processed actions & save timestamp
    38→  await clearProcessedActions(response.processed_actions.map(a => a.action_id));
    39→  await AsyncStorage.setItem(KEYS.LAST_SYNC, response.sync_timestamp);
    40→
    41→  return response;
    42→}
    43→
    44→export async function addOfflineAction(type: string, data: unknown): Promise<void> {
    45→  const action: OfflineAction = {
    46→    id: `action-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`,
    47→    type, data, timestamp: new Date().toISOString(),
    48→  };
    49→  const queue = await getOfflineActions();
    50→  queue.push(action);
    51→  await AsyncStorage.setItem(KEYS.OFFLINE_QUEUE, JSON.stringify(queue));
    52→}
    53→
    54→export async function getOfflineActions(): Promise<OfflineAction[]> {
    55→  const json = await AsyncStorage.getItem(KEYS.OFFLINE_QUEUE);
    56→  return json ? JSON.parse(json) : [];
    57→}
    58→
    59→export async function clearSyncData(): Promise<void> {
    60→  await AsyncStorage.multiRemove([KEYS.SYNC_TOKEN, KEYS.LAST_SYNC, KEYS.OFFLINE_QUEUE]);
    61→}
    62→
    63→async function clearProcessedActions(ids: string[]): Promise<void> {
    64→  const queue = await getOfflineActions();
    65→  await AsyncStorage.setItem(KEYS.OFFLINE_QUEUE, JSON.stringify(queue.filter(a => !ids.includes(a.id))));
    66→}
