   334→async function getWebCryptoRandomBytes(length: number): Promise<Uint8Array> {
   335→  const bytes = new Uint8Array(length);
   336→  try {
   337→    if (globalThis.crypto && typeof globalThis.crypto.getRandomValues === 'function') {
   338→      globalThis.crypto.getRandomValues(bytes);
   339→    } else {
   340→      // Fallback: use Math.random (only for development/testing)
   341→      for (let i = 0; i < length; i++) {
   342→        bytes[i] = Math.floor(Math.random() * 256);
   343→      }
   344→    }
   345→  } catch {
   346→    for (let i = 0; i < length; i++) {
   347→      bytes[i] = Math.floor(Math.random() * 256);
   348→    }
   349→  }
   350→  return bytes;
   351→}
   352→
   353→async function sha256Hex(input: string): Promise<string> {
   354→  // Try expo-crypto first (native)
   355→  try {
   356→    const { default: ExpoCrypto } = await import('expo-crypto');
   357→    return await ExpoCrypto.digestStringAsync(ExpoCrypto.CryptoDigestAlgorithm.SHA256, input);
   358→  } catch {
   359→    // Fallback: use js-sha256 (pure JS, works everywhere)
   360→    const { sha256 } = await import('js-sha256');
   361→    return sha256(input);
   362→  }
   363→}
   364→
   365→async function generateKeyPair(): Promise<{ publicKey: string; privateKey: string }> {
   366→  // Simple key generation using random bytes encoded as hex
   367→  let privBytes: Uint8Array;
   368→  try {
   369→    const { default: ExpoCrypto } = await import('expo-crypto');
   370→    privBytes = await ExpoCrypto.getRandomBytesAsync(32);
   371→  } catch {
   372→    privBytes = await getWebCryptoRandomBytes(32);
   373→  }
   374→  const privHex = Array.from(privBytes).map(b => b.toString(16).padStart(2, '0')).join('');
   375→  // For Ed25519, public key would normally be derived — use SHA256 hash as placeholder
   376→  const pubHex = await sha256Hex(privHex);
   377→  return { publicKey: pubHex, privateKey: privHex };
   378→}
