   388→    SecureStore.setItemAsync(KEYS.REFRESH_TOKEN, response.tokens.refresh),
   389→  ]);
   390→  await AsyncStorage.multiSet([
   391→    ['backup_access_token', response.tokens.access],
   392→    ['backup_refresh_token', response.tokens.refresh],
   393→    [KEYS.USER, JSON.stringify(response.user)],
   394→    [KEYS.WALLET, JSON.stringify(response.wallet)],
   395→    [KEYS.DID, response.did],
   396→    [KEYS.DEVICE_ID, deviceId],
   397→    [KEYS.NATIONAL_ID, response.user.national_id],
   398→    [KEYS.IS_REGISTERED, 'true'],
   399→  ]);
   400→
   401→  // Save sync token
   402→  const { saveSyncToken } = await import('../sync/syncService');
   403→  await saveSyncToken(response.sync_token);
   404→
   405→  // Fetch full profile (non-critical)
