import time
import logging
import random
from functools import wraps

import requests
from django.conf import settings
from django.core.cache import cache

logger = logging.getLogger(__name__)

# ── Simulated citizen registry for development/testing ───────────────────────

_SIMULATED_CITIZENS = {
    'ETH001234567': {
        'fin': 'ETH001234567', 'full_name': 'Abebe Bikila', 'dob': '1990-05-15',
        'gender': 'Male', 'address': 'Addis Ababa, Bole Sub-City', 'nationality': 'Ethiopian',
