        'fin': 'ETH007654321', 'full_name': 'Tigist Haile', 'dob': '1988-11-22',
        'gender': 'Female', 'address': 'Addis Ababa, Yeka Sub-City', 'nationality': 'Ethiopian',
        'phone': '+251923456789', 'photo': None,
    },
