        'gender': 'Male', 'address': 'Test Address, Test City', 'nationality': 'Ethiopian',
        'phone': '+251900000000', 'photo': None,
    },
}

# Any OTP is accepted in simulation mode; "000000" is the canonical test OTP.
_SIMULATION_OTP = '000000'


class NationalIDServiceError(ValueError):
    """Raised when the upstream NID service returns an error."""

    def __init__(self, message: str, status_code: int = 400):
        super().__init__(message)
        self.status_code = status_code


class CircuitBreaker:
    """
    Simple circuit breaker for external service calls.
    After `failure_threshold` consecutive failures, the circuit
    opens and all calls fail fast for `reset_timeout` seconds.
    """

    def __init__(self, name: str, failure_threshold: int = 3, reset_timeout: int = 60):
        self.name = name
        self.failure_threshold = failure_threshold
        self.reset_timeout = reset_timeout

    def _cache_key(self, suffix: str) -> str:
        return f"circuit_breaker:{self.name}:{suffix}"

    @property
    def is_open(self) -> bool:
        opened_at = cache.get(self._cache_key("opened_at"))
        if opened_at is None:
            return False
        if time.time() - opened_at > self.reset_timeout:
            cache.delete(self._cache_key("opened_at"))
            cache.delete(self._cache_key("failure_count"))
            return False
        return True

    def record_failure(self):
        key = self._cache_key("failure_count")
        count = cache.get(key, 0) + 1
        cache.set(key, count, self.reset_timeout * 2)
        if count >= self.failure_threshold:
            cache.set(self._cache_key("opened_at"), time.time(), self.reset_timeout * 2)
            logger.warning("Circuit breaker %s OPENED after %d failures", self.name, count)

    def record_success(self):
        cache.delete(self._cache_key("failure_count"))
        cache.delete(self._cache_key("opened_at"))


def circuit_breaker(name: str, fallback_return=None):
    """Decorator that wraps a method with circuit breaker logic."""
    breaker = CircuitBreaker(name)

    def decorator(func):
        @wraps(func)
        def wrapper(self, *args, **kwargs):
            if breaker.is_open:
                logger.warning("Circuit breaker %s is open — returning fallback", name)
                if fallback_return is not None:
                    return fallback_return
                raise NationalIDServiceError(
                    "NID service is temporarily unavailable (circuit open). "
                    "Please try again later.",
                    status_code=503,
                )
            try:
                result = func(self, *args, **kwargs)
                breaker.record_success()
                return result
            except (requests.RequestException, NationalIDServiceError) as e:
                breaker.record_failure()
                raise
        return wrapper
    return decorator


class NationalIDService:
    """
    Dedicated service to handle communication with the External/Simulated
    National ID system.

    In simulation mode (NID_SIMULATION_MODE=True or when the external service
    is unreachable), uses a built-in citizen registry for development and testing.

    Implements:
    - Caching of profile data to reduce external calls
    - Circuit breaker to handle service outages gracefully
    - Retry with exponential backoff
    - Graceful fallback to simulation mode
    """

    DEFAULT_BASE_URL = 'http://localhost:8001/nid'

    def __init__(self, base_url: str | None = None):
        configured_base_url = base_url or getattr(settings, 'NID_SERVICE_URL', self.DEFAULT_BASE_URL)
        self.base_url = configured_base_url.rstrip('/')
        self._session = requests.Session()
        self._session.timeout = 5
        self._simulation = getattr(settings, 'NID_SIMULATION_MODE', True)

    def _is_simulation(self) -> bool:
        return self._simulation

    def _build_url(self, path: str) -> str:
        return f"{self.base_url}/{path.strip('/')}/"

    @staticmethod
    def _extract_error_message(response: requests.Response) -> str:
        try:
            payload = response.json()
        except ValueError:
            return response.text.strip() or response.reason

        if isinstance(payload, dict):
            return payload.get('error') or payload.get('message') or response.reason

        return response.reason

    def _raise_service_error(self, response: requests.Response, fin: str, error_label: str):
        if response.status_code == 404:
            raise NationalIDServiceError(
                f"FIN {fin} was not found in the NID service",
                status_code=response.status_code,
            )

        raise NationalIDServiceError(
            f"NID Service {error_label} Error: {self._extract_error_message(response)}",
            status_code=response.status_code,
        )

    def _request_with_retry(self, method: str, url: str, **kwargs) -> requests.Response:
        """Make an HTTP request with exponential backoff retry."""
        max_retries = 2
        for attempt in range(max_retries + 1):
            try:
                response = self._session.request(method, url, **kwargs)
                return response
            except requests.RequestException as e:
                if attempt < max_retries:
                    wait = 2 ** attempt
                    logger.warning("NID request failed (attempt %d/%d): %s. Retrying in %ds...",
                                   attempt + 1, max_retries + 1, e, wait)
                    time.sleep(wait)
                else:
                    raise
        raise RuntimeError("unreachable")

    def _simulate_check_fin(self, fin: str) -> dict:
        """Simulation: validate FIN and return masked phone number."""
        fin_upper = fin.strip().upper()
        if len(fin_upper) < 6:
            raise NationalIDServiceError(
                "Invalid National ID format. Must be at least 6 characters.",
                status_code=400,
            )

        citizen = _SIMULATED_CITIZENS.get(fin_upper)
        if citizen:
            phone = citizen['phone']
            masked = '*' * (len(phone) - 4) + phone[-4:]
        else:
            # Accept any FIN with proper length in simulation mode
            masked = '****' + str(random.randint(1000, 9999))

        # Store the FIN->OTP mapping in cache for verify step
        cache.set(f"sim_nid_fin:{fin_upper}", True, timeout=600)
        logger.info("[NID-SIM] check_fin: FIN=%s, masked_phone=%s", fin_upper, masked)
        print(f"\n{'='*60}")
        print(f"📱 [NID SIMULATION] OTP REQUEST")
        print(f"   FIN: {fin_upper}")
        print(f"   Use any 6-digit OTP (e.g. 000000) on next screen")
        print(f"{'='*60}\n")
        return {'fin': fin_upper, 'phone': masked, 'status': 'otp_sent'}

    def _simulate_verify_otp(self, fin: str, otp: str) -> bool:
        """Simulation: accept any 6-digit numeric OTP."""
        fin_upper = fin.strip().upper()
        if not otp or not otp.strip().isdigit() or len(otp.strip()) != 6:
            logger.info("[NID-SIM] verify_otp: invalid OTP format for FIN=%s", fin_upper)
            return False
        logger.info("[NID-SIM] verify_otp: FIN=%s OTP=%s -> VERIFIED", fin_upper, otp)
        print(f"\n{'='*60}")
        print(f"✅ [NID SIMULATION] OTP VERIFIED for FIN: {fin_upper}")
        print(f"{'='*60}\n")
        return True

    def _simulate_get_profile(self, fin: str) -> dict:
        """Simulation: return citizen profile from the registry."""
        fin_upper = fin.strip().upper()
        citizen = _SIMULATED_CITIZENS.get(fin_upper)
        if citizen:
            return dict(citizen)
        # Generate a synthetic profile for any unknown FIN
        return {
            'fin': fin_upper,
            'full_name': f'Citizen {fin_upper[-4:]}',
            'dob': '1990-01-01',
            'gender': 'Male',
            'address': 'Addis Ababa, Ethiopia',
            'nationality': 'Ethiopian',
            'phone': f'+2519{fin_upper[-8:].zfill(8)[:8]}',
            'photo': None,
        }

    @circuit_breaker("nid_check_fin")
    def check_fin(self, fin: str) -> dict:
        """Triggers an OTP for the given FIN."""
        if self._is_simulation():
            return self._simulate_check_fin(fin)

        try:
            response = self._request_with_retry(
                'GET', self._build_url('check-fin'), params={"fin": fin}
            )
        except requests.RequestException as e:
            logger.warning("NID external service unreachable, falling back to simulation: %s", e)
            return self._simulate_check_fin(fin)

        if not response.ok:
            self._raise_service_error(response, fin, 'Check')

        try:
            return response.json()
        except ValueError as e:
            raise NationalIDServiceError(f"NID Service Check Error: Invalid JSON response: {str(e)}")

    @circuit_breaker("nid_verify_otp")
    def verify_otp(self, fin: str, otp: str) -> bool:
        """Verifies the OTP for a specific FIN."""
        if self._is_simulation():
            return self._simulate_verify_otp(fin, otp)

        try:
            response = self._request_with_retry(
                'GET', self._build_url('verify-otp'), params={"fin": fin, "otp": otp}
            )
        except requests.RequestException as e:
            logger.warning("NID external service unreachable, falling back to simulation: %s", e)
            return self._simulate_verify_otp(fin, otp)

        if response.ok:
            try:
                return response.json().get('verified', False)
            except ValueError as e:
                raise NationalIDServiceError(f"NID Service Verify Error: Invalid JSON response: {str(e)}")

        try:
            payload = response.json()
        except ValueError:
            payload = None

        if isinstance(payload, dict) and payload.get('verified') is False:
            return False

        self._raise_service_error(response, fin, 'Verify')

    @circuit_breaker("nid_get_profile", fallback_return=None)
    def get_profile(self, fin: str) -> dict:
        """Fetches the full verified profile data from NID."""
        cached = cache.get(f"nid_profile_{fin}")
        if cached and isinstance(cached, dict) and cached.get('full_name'):
            logger.debug("Returning cached NID profile for %s", fin)
            return cached

        if self._is_simulation():
            data = self._simulate_get_profile(fin)
            cache.set(f"nid_profile_{fin}", data, timeout=600)
            return data

        try:
            response = self._request_with_retry(
                'GET', self._build_url('get-profile'), params={"fin": fin}
            )
        except requests.RequestException as e:
            cached_profile = cache.get(f"nid_profile_{fin}")
            if cached_profile:
                logger.warning("NID fetch failed, returning stale cache for %s", fin)
                return cached_profile
            logger.warning("NID external service unreachable, using simulation for %s: %s", fin, e)
            return self._simulate_get_profile(fin)

        if not response.ok:
            cached_profile = cache.get(f"nid_profile_{fin}")
            if cached_profile:
                logger.warning("NID returned error, returning stale cache for %s", fin)
                return cached_profile
            self._raise_service_error(response, fin, 'Profile')

        try:
            data = response.json()
            cache.set(f"nid_profile_{fin}", data, timeout=600)
            return data
        except ValueError as e:
            raise NationalIDServiceError(f"NID Service Profile Error: Invalid JSON response: {str(e)}")

import axios from 'axios';
import { toast } from 'sonner';

const API_BASE_URL = import.meta.env.VITE_API_URL
  || import.meta.env.VITE_API_BASE_URL
  || 'http://localhost:8000/api';

export const baseClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
  withCredentials: false,
});

// Request Interceptor: Inject Auth Token
baseClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('authToken') || localStorage.getItem('auth_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Track whether a token refresh is in progress to avoid infinite loops
let _refreshPromise: Promise<string | null> | null = null;

async function attemptTokenRefresh(): Promise<string | null> {
  if (_refreshPromise) return _refreshPromise;

  _refreshPromise = (async () => {
    const refreshToken = localStorage.getItem('refreshToken');
    if (!refreshToken) return null;
    try {
      const resp = await axios.post(`${API_BASE_URL.replace(/\/api$/, '')}/api/token/refresh/`, {
        refresh: refreshToken,
      });
      const newAccess: string = resp.data?.access;
      const newRefresh: string | undefined = resp.data?.refresh;
      if (newAccess) {
        localStorage.setItem('authToken', newAccess);
        if (newRefresh) localStorage.setItem('refreshToken', newRefresh);
        return newAccess;
      }
      return null;
    } catch {
      return null;
    } finally {
      _refreshPromise = null;
    }
  })();

  return _refreshPromise;
}

function clearSession() {
  localStorage.removeItem('authToken');
  localStorage.removeItem('auth_token');
  localStorage.removeItem('refreshToken');
  localStorage.removeItem('user');
  localStorage.removeItem('userEmail');
  localStorage.removeItem('userName');
  localStorage.removeItem('userRole');
  localStorage.removeItem('userRoles');
  window.dispatchEvent(new CustomEvent('auth:logout'));
}

// Response Interceptor: Auto-refresh on 401, handle other errors
baseClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    const status = error.response?.status;
    const originalRequest = error.config;

    if (status === 401 && !originalRequest._retried) {
      originalRequest._retried = true;

      const newToken = await attemptTokenRefresh();
      if (newToken) {
        originalRequest.headers.Authorization = `Bearer ${newToken}`;
        return baseClient(originalRequest);
      }

      // Refresh failed — clear session and redirect
      clearSession();
      const publicPaths = ['/login', '/register', '/auth/', '/'];
      const currentPath = window.location.pathname;
      const isPublic = publicPaths.some(p => currentPath.startsWith(p));
      if (!isPublic) {
        toast.error('Session expired. Please log in again.');
        window.location.href = '/?openLogin=true';
      }
      return Promise.reject(error);
    }

    if (status === 429) {
      toast.error('Too many requests. Please wait a moment before trying again.');
    } else if (status === 403) {
      const errorCode = error.response?.data?.error;
      const suppressedCodes = ['PENDING_APPROVAL', 'REJECTED'];
      if (!errorCode || !suppressedCodes.includes(errorCode)) {
        toast.error("You don't have permission to perform this action.");
      }
    } else if (status === 404) {
      // Silently handle 404 — let the calling code handle it
    } else if (status && status >= 500) {
      toast.error('Server error. Please try again later.');
    }

    return Promise.reject(error);
  }
);

export default baseClient;

